// GSD Client — IPC abstraction layer
// This is the ONLY file in the frontend that may import @tauri-apps/api (D005).

import { invoke } from "@tauri-apps/api/core";
import { listen } from "@tauri-apps/api/event";

import type {
  RpcCommand,
  QuerySnapshot,
  ProjectInfo,
  SavedProject,
  GsdEventPayload,
  GsdExitPayload,
  GsdErrorPayload,
  GsdFileChangedPayload,
} from "@/lib/types";

// Re-export types so downstream consumers import from gsd-client (D005 boundary)
export type {
  RpcCommand,
  QuerySnapshot,
  ProjectInfo,
  SavedProject,
  GsdEventPayload,
  GsdExitPayload,
  GsdErrorPayload,
  GsdFileChangedPayload,
} from "@/lib/types";

// ---------------------------------------------------------------------------
// GsdClient interface
// ---------------------------------------------------------------------------

export interface GsdClient {
  // Commands (invoke-based)
  startSession: (projectPath: string) => Promise<void>;
  stopSession: () => Promise<void>;
  sendCommand: (command: RpcCommand) => Promise<void>;
  queryState: (projectPath: string) => Promise<QuerySnapshot>;
  listProjects: (scanPath: string) => Promise<ProjectInfo[]>;
  startFileWatcher: (projectPath: string) => Promise<void>;
  stopFileWatcher: () => Promise<void>;
  // Project registry
  getSavedProjects: () => Promise<SavedProject[]>;
  addProject: (projectPath: string, description?: string) => Promise<SavedProject>;
  removeProject: (projectId: string) => Promise<void>;
  // Event listeners (listen-based) — return unlisten functions
  onGsdEvent: (
    handler: (payload: GsdEventPayload) => void,
  ) => Promise<() => void>;
  onProcessExit: (
    handler: (payload: GsdExitPayload) => void,
  ) => Promise<() => void>;
  onProcessError: (
    handler: (payload: GsdErrorPayload) => void,
  ) => Promise<() => void>;
  onFileChanged: (
    handler: (payload: GsdFileChangedPayload) => void,
  ) => Promise<() => void>;
}

// ---------------------------------------------------------------------------
// Factory
// ---------------------------------------------------------------------------

export function createGsdClient(): GsdClient {
  return {
    // ---- invoke-based commands ----
    startSession: (projectPath: string) =>
      invoke("start_gsd_session", { projectPath }),

    stopSession: () => invoke("stop_gsd_session"),

    sendCommand: (command: RpcCommand) =>
      invoke("send_gsd_command", { command: JSON.stringify(command) }),

    queryState: (projectPath: string) =>
      invoke<QuerySnapshot>("query_gsd_state", { projectPath }),

    listProjects: (scanPath: string) =>
      invoke<ProjectInfo[]>("list_projects", { scanPath }),

    startFileWatcher: (projectPath: string) =>
      invoke("start_file_watcher", { projectPath }),

    stopFileWatcher: () => invoke("stop_file_watcher"),

    // ---- project registry ----
    getSavedProjects: () =>
      invoke<SavedProject[]>("get_saved_projects"),

    addProject: (projectPath: string, description?: string) =>
      invoke<SavedProject>("add_project", { projectPath, description: description ?? null }),

    removeProject: (projectId: string) =>
      invoke("remove_project", { projectId }),

    // ---- listen-based event subscriptions ----
    onGsdEvent: (handler) =>
      listen<GsdEventPayload>("gsd-event", (event) =>
        handler(event.payload),
      ).then((unlisten) => unlisten),

    onProcessExit: (handler) =>
      listen<GsdExitPayload>("gsd-process-exit", (event) =>
        handler(event.payload),
      ).then((unlisten) => unlisten),

    onProcessError: (handler) =>
      listen<GsdErrorPayload>("gsd-process-error", (event) =>
        handler(event.payload),
      ).then((unlisten) => unlisten),

    onFileChanged: (handler) =>
      listen<GsdFileChangedPayload>("gsd-file-changed", (event) =>
        handler(event.payload),
      ).then((unlisten) => unlisten),
  };
}

import { describe, it, expect, beforeEach, vi } from "vitest";
import { setupTauriMocks } from "@/test/tauri-mock";
import { createGsdClient } from "@/services/gsd-client";
import type { GsdClient } from "@/services/gsd-client";
import type { RpcCommand, QuerySnapshot, ProjectInfo, SavedProject } from "@/lib/types";

// vi.mock calls are hoisted — setupTauriMocks uses vi.hoisted() internally
const { mockInvoke, mockListen } = setupTauriMocks();

describe("gsd-client", () => {
  beforeEach(() => {
    mockInvoke.mockReset().mockResolvedValue(undefined);
    mockListen.mockReset().mockResolvedValue(vi.fn());
  });

  // ---- factory ----

  it("createGsdClient() returns an object with all expected methods", () => {
    const client: GsdClient = createGsdClient();
    expect(typeof client.startSession).toBe("function");
    expect(typeof client.stopSession).toBe("function");
    expect(typeof client.sendCommand).toBe("function");
    expect(typeof client.queryState).toBe("function");
    expect(typeof client.listProjects).toBe("function");
    expect(typeof client.startFileWatcher).toBe("function");
    expect(typeof client.stopFileWatcher).toBe("function");
    expect(typeof client.onGsdEvent).toBe("function");
    expect(typeof client.onProcessExit).toBe("function");
    expect(typeof client.onProcessError).toBe("function");
    expect(typeof client.onFileChanged).toBe("function");
    expect(typeof client.getSavedProjects).toBe("function");
    expect(typeof client.addProject).toBe("function");
    expect(typeof client.removeProject).toBe("function");
  });

  // ---- invoke-based commands ----

  it("startSession() calls invoke with correct command and args", async () => {
    const client = createGsdClient();
    await client.startSession("/projects/my-app");
    expect(mockInvoke).toHaveBeenCalledWith("start_gsd_session", {
      projectPath: "/projects/my-app",
    });
  });

  it("stopSession() calls invoke with correct command", async () => {
    const client = createGsdClient();
    await client.stopSession();
    expect(mockInvoke).toHaveBeenCalledWith("stop_gsd_session");
  });

  it("sendCommand() calls invoke with stringified command", async () => {
    const client = createGsdClient();
    const command: RpcCommand = { type: "prompt", text: "hello" };
    await client.sendCommand(command);
    expect(mockInvoke).toHaveBeenCalledWith("send_gsd_command", {
      command: JSON.stringify(command),
    });
  });

  it("queryState() calls invoke and returns QuerySnapshot", async () => {
    const snapshot: QuerySnapshot = {
      currentMilestone: "M001",
      activeTasks: 3,
      totalCost: 12.5,
    };
    mockInvoke.mockResolvedValue(snapshot);
    const client = createGsdClient();
    const result = await client.queryState("/projects/my-app");
    expect(mockInvoke).toHaveBeenCalledWith("query_gsd_state", {
      projectPath: "/projects/my-app",
    });
    expect(result).toEqual(snapshot);
  });

  it("listProjects() calls invoke and returns ProjectInfo array", async () => {
    const projects: ProjectInfo[] = [
      { id: "p1", name: "Alpha", path: "/alpha" },
    ];
    mockInvoke.mockResolvedValue(projects);
    const client = createGsdClient();
    const result = await client.listProjects("/scan");
    expect(mockInvoke).toHaveBeenCalledWith("list_projects", {
      scanPath: "/scan",
    });
    expect(result).toEqual(projects);
  });

  it("startFileWatcher() calls invoke with correct args", async () => {
    const client = createGsdClient();
    await client.startFileWatcher("/projects/my-app");
    expect(mockInvoke).toHaveBeenCalledWith("start_file_watcher", {
      projectPath: "/projects/my-app",
    });
  });

  it("stopFileWatcher() calls invoke with correct command", async () => {
    const client = createGsdClient();
    await client.stopFileWatcher();
    expect(mockInvoke).toHaveBeenCalledWith("stop_file_watcher");
  });

  // ---- project registry commands ----

  it("getSavedProjects() calls invoke and returns SavedProject array", async () => {
    const saved: SavedProject[] = [
      { id: "p1", name: "alpha", path: "/alpha", description: null, addedAt: "123" },
    ];
    mockInvoke.mockResolvedValue(saved);
    const client = createGsdClient();
    const result = await client.getSavedProjects();
    expect(mockInvoke).toHaveBeenCalledWith("get_saved_projects");
    expect(result).toEqual(saved);
  });

  it("addProject() calls invoke with path and description", async () => {
    const saved: SavedProject = {
      id: "p1", name: "my-app", path: "/my-app", description: "desc", addedAt: "123",
    };
    mockInvoke.mockResolvedValue(saved);
    const client = createGsdClient();
    const result = await client.addProject("/my-app", "desc");
    expect(mockInvoke).toHaveBeenCalledWith("add_project", {
      projectPath: "/my-app",
      description: "desc",
    });
    expect(result).toEqual(saved);
  });

  it("addProject() passes null description when omitted", async () => {
    mockInvoke.mockResolvedValue({});
    const client = createGsdClient();
    await client.addProject("/path");
    expect(mockInvoke).toHaveBeenCalledWith("add_project", {
      projectPath: "/path",
      description: null,
    });
  });

  it("removeProject() calls invoke with project ID", async () => {
    const client = createGsdClient();
    await client.removeProject("p1");
    expect(mockInvoke).toHaveBeenCalledWith("remove_project", {
      projectId: "p1",
    });
  });

  // ---- listen-based event subscriptions ----

  it("onGsdEvent() calls listen with correct event name", async () => {
    const client = createGsdClient();
    const handler = vi.fn();
    await client.onGsdEvent(handler);
    expect(mockListen).toHaveBeenCalledWith("gsd-event", expect.any(Function));
  });

  it("onProcessExit() calls listen and returns unlisten function", async () => {
    const mockUnlisten = vi.fn();
    mockListen.mockResolvedValue(mockUnlisten);
    const client = createGsdClient();
    const unlisten = await client.onProcessExit(vi.fn());
    expect(mockListen).toHaveBeenCalledWith(
      "gsd-process-exit",
      expect.any(Function),
    );
    expect(unlisten).toBe(mockUnlisten);
  });

  it("onProcessError() calls listen with correct event name", async () => {
    const client = createGsdClient();
    const handler = vi.fn();
    await client.onProcessError(handler);
    expect(mockListen).toHaveBeenCalledWith(
      "gsd-process-error",
      expect.any(Function),
    );
  });

  it("onFileChanged() calls listen with correct event name", async () => {
    const client = createGsdClient();
    const handler = vi.fn();
    await client.onFileChanged(handler);
    expect(mockListen).toHaveBeenCalledWith(
      "gsd-file-changed",
      expect.any(Function),
    );
  });

  // ---- error propagation ----

  it("invoke failure propagates as rejected promise", async () => {
    mockInvoke.mockRejectedValue(new Error("Tauri IPC error"));
    const client = createGsdClient();
    await expect(client.startSession("/bad")).rejects.toThrow(
      "Tauri IPC error",
    );
  });

  // ---- event handler invocation ----

  it("onGsdEvent() wrapper passes event.payload to handler", async () => {
    const handler = vi.fn();
    // Capture the internal callback that listen receives
    mockListen.mockImplementation(async (_event: string, cb: Function) => {
      // Simulate Tauri calling the callback with an event envelope
      cb({ payload: { raw: '{"type":"agent_start"}', timestamp: 1000 } });
      return vi.fn();
    });
    const client = createGsdClient();
    await client.onGsdEvent(handler);
    expect(handler).toHaveBeenCalledWith({
      raw: '{"type":"agent_start"}',
      timestamp: 1000,
    });
  });
});

// ---------------------------------------------------------------------------
// Shared TypeScript types mirroring Rust IPC structs
// This is the single source of truth for all frontend ↔ Tauri boundary types.
// ---------------------------------------------------------------------------

// ---------------------------------------------------------------------------
// RPC Commands (frontend → GSD process via stdin)
// Mirrors: src-tauri/src/gsd_rpc.rs — RpcCommand
// serde(tag = "type", rename_all = "snake_case")
// ---------------------------------------------------------------------------

export type RpcCommand =
  | { type: "prompt"; text: string }
  | { type: "steer"; text: string }
  | { type: "abort" }
  | { type: "get_state" }
  | { type: "set_model"; model: string }
  | { type: "get_available_models" }
  | { type: "get_session_stats" }
  | { type: "get_messages" }
  | { type: "new_session" };

// ---------------------------------------------------------------------------
// RPC Events (GSD process → frontend via stdout)
// Mirrors: src-tauri/src/gsd_rpc.rs — RpcEvent
// serde(tag = "type", rename_all = "snake_case")
// Field names stay snake_case in JSON (no rename_all on struct fields).
// ---------------------------------------------------------------------------

export type RpcEvent =
  | { type: "agent_start"; session_id: string }
  | { type: "agent_end"; session_id: string }
  | { type: "assistant_message"; content: string; done: boolean }
  | { type: "tool_execution_start"; tool: string; id: string }
  | { type: "tool_execution_end"; tool: string; id: string; success: boolean }
  | {
      type: "extension_ui_request";
      request_id: string;
      kind: string;
      payload: unknown;
    }
  | { type: "session_state_changed"; payload: unknown }
  | { type: "error"; message: string };

// ---------------------------------------------------------------------------
// Query types
// Mirrors: src-tauri/src/gsd_query.rs
// serde(rename_all = "camelCase")
// ---------------------------------------------------------------------------

/** Snapshot of GSD project state, returned by `query_gsd_state` command. */
export interface QuerySnapshot {
  currentMilestone: string | null;
  activeTasks: number;
  totalCost: number;
}

/** A discovered GSD project directory. */
export interface ProjectInfo {
  id: string;
  name: string;
  path: string;
}

/** A project stored in the persistent registry. */
export interface SavedProject {
  id: string;
  name: string;
  path: string;
  description: string | null;
  addedAt: string;
}

/** Extended project info for gallery display. Built client-side from ProjectInfo + QuerySnapshot. */
export interface ProjectDisplayInfo extends ProjectInfo {
  status: "active" | "paused" | "idle";
  currentMilestone: string | null;
  totalCost: number;
  progress: number; // 0-100
  lastActivity: string | null; // ISO timestamp or null
}

// ---------------------------------------------------------------------------
// Milestone / Slice / Task tree types (for progress dashboard & roadmap)
// ---------------------------------------------------------------------------

export type CompletionStatus = "done" | "in-progress" | "pending" | "blocked";
export type RiskLevel = "low" | "medium" | "high";

export interface TaskInfo {
  id: string;
  title: string;
  status: CompletionStatus;
  cost: number;
  duration: string | null;
}

export interface SliceInfo {
  id: string;
  title: string;
  status: CompletionStatus;
  risk: RiskLevel;
  cost: number;
  progress: number; // 0-100
  tasks: TaskInfo[];
  depends: string[];
}

export interface MilestoneInfo {
  id: string;
  title: string;
  status: CompletionStatus;
  cost: number;
  progress: number; // 0-100
  slices: SliceInfo[];
}

// ---------------------------------------------------------------------------
// Cost data types (for cost overview charts)
// ---------------------------------------------------------------------------

export interface CostByPhase {
  phase: string;
  cost: number;
}

export interface CostByModel {
  model: string;
  cost: number;
}

export interface CostData {
  totalCost: number;
  budgetCeiling: number | null;
  byPhase: CostByPhase[];
  byModel: CostByModel[];
  bySlice: { sliceId: string; title: string; cost: number }[];
}

// ---------------------------------------------------------------------------
// Session types (for session browser)
// ---------------------------------------------------------------------------

export interface SessionInfo {
  id: string;
  name: string;
  messageCount: number;
  cost: number;
  createdAt: string; // ISO
  lastActiveAt: string; // ISO
  preview: string; // first message preview
  parentId: string | null;
  isActive: boolean;
}

// ---------------------------------------------------------------------------
// Process event payloads
// Mirrors: src-tauri/src/gsd_process.rs
// No rename_all — fields are single-word, so no casing issue.
// ---------------------------------------------------------------------------

/** Payload emitted as a `gsd-event` Tauri event for each JSONL line from stdout. */
export interface GsdEventPayload {
  raw: string;
  timestamp: number;
}

/** Payload emitted as `gsd-process-exit`. */
export interface GsdExitPayload {
  code: number | null;
  timestamp: number;
}

/** Payload emitted as `gsd-process-error`. */
export interface GsdErrorPayload {
  message: string;
  timestamp: number;
}

// ---------------------------------------------------------------------------
// File watcher payload
// Mirrors: src-tauri/src/gsd_watcher.rs
// serde(rename_all = "camelCase") — but all fields are single-word anyway.
// ---------------------------------------------------------------------------

/** Payload for `gsd-file-changed` events. */
export interface GsdFileChangedPayload {
  path: string;
  kind: string;
  timestamp: number;
}

// ---------------------------------------------------------------------------
// Session state
// ---------------------------------------------------------------------------

/** Possible states of the GSD agent session. */
export type SessionState =
  | "idle"
  | "connecting"
  | "connected"
  | "streaming"
  | "disconnected"
  | "error";

